  function bindRuntimeErrorWarnings() {
    if (typeof window === 'undefined' || window.__sheafCalculatorRuntimeWarningsBound) return;
    window.__sheafCalculatorRuntimeWarningsBound = true;
    window.addEventListener('error', (event) => {
      reportInputActionError(event.error || event.message || new Error('Unexpected JavaScript error.'));
    });
    window.addEventListener('unhandledrejection', (event) => {
      reportInputActionError(event.reason || new Error('Unexpected asynchronous JavaScript error.'));
    });
  }

  function initCustomTooltips() {
    if (typeof document === 'undefined' || !document.body || document.body.dataset.customTooltipsReady === '1') return;
    document.body.dataset.customTooltipsReady = '1';

    const tip = document.createElement('div');
    tip.className = 'custom-tooltip';
    tip.setAttribute('role', 'tooltip');
    document.body.appendChild(tip);

    let activeEl = null;

    const placeTooltip = (el) => {
      const rect = el.getBoundingClientRect();
      const margin = 10;
      const gap = 8;
      tip.style.left = '0px';
      tip.style.top = '0px';
      const tipRect = tip.getBoundingClientRect();
      let left = rect.left + rect.width / 2 - tipRect.width / 2;
      left = Math.max(margin, Math.min(left, window.innerWidth - tipRect.width - margin));
      let top = rect.top - tipRect.height - gap;
      if (top < margin) top = rect.bottom + gap;
      top = Math.max(margin, Math.min(top, window.innerHeight - tipRect.height - margin));
      tip.style.left = `${Math.round(left)}px`;
      tip.style.top = `${Math.round(top)}px`;
    };

    const showTooltip = (el) => {
      const text = el.getAttribute('data-tooltip');
      if (!text) return;
      activeEl = el;
      tip.textContent = text;
      tip.classList.add('visible');
      placeTooltip(el);
    };

    const hideTooltip = (el) => {
      if (el && activeEl && el !== activeEl) return;
      tip.classList.remove('visible');
      activeEl = null;
    };

    document.addEventListener('pointerenter', (event) => {
      const el = event.target?.closest?.('[data-tooltip]');
      if (el) showTooltip(el);
    }, true);
    document.addEventListener('pointerleave', (event) => {
      const el = event.target?.closest?.('[data-tooltip]');
      if (el) hideTooltip(el);
    }, true);
    document.addEventListener('focusin', (event) => {
      const el = event.target?.closest?.('[data-tooltip]');
      if (el) showTooltip(el);
    });
    document.addEventListener('focusout', (event) => {
      const el = event.target?.closest?.('[data-tooltip]');
      if (el) hideTooltip(el);
    });
    window.addEventListener('scroll', () => {
      if (activeEl) placeTooltip(activeEl);
    }, true);
    window.addEventListener('resize', () => {
      if (activeEl) placeTooltip(activeEl);
    });
  }

