        kind: embeddedGeometrySupportsLineCohomology(geometry) ? 'line' : 'unsupported',
        twist: -1,
        subjectLatex: sheafLabelLatex(sheaf),
        subjectPlain: sheafLabelPlain(sheaf),
        message: embeddedGeometrySupportsLineCohomology(geometry)
