      kind: 'unsupported',
      subjectLatex: sheafLabelLatex(sheaf),
      subjectPlain: sheafLabelPlain(sheaf),
      message: `Cohomology of ${sheafTypeLabel(sheaf.type)} is not determined by the current input.`
